INSERT INTO `catalog_pages` (`id`, `parent_id`, `caption`, `page_layout`, `icon_image`, `min_rank`, `order_num`, `visible`, `enabled`, `link`, `type`, `extra_data`, `page_headline`, `page_teaser`, `page_special`, `page_text_1`, `page_text_2`, `page_text_details`) VALUES (1,-1,'Front Page','frontpage',213,1,1,'1','1','front_page','NORMAL','','catalog_frontpage_headline_shop_EN','','','','Redeem a voucher code here:',''),(2,-1,'Furni','default_3x3',263,1,2,'1','1','furni','NORMAL','','catalog_header_roombuilder','cr_infopic3','','','Furni Shop',NULL),(3,-1,'Clothing','default_3x3',37,1,3,'1','1','clothing','NORMAL','','catalog_frontpage_headline_shop_EN','','','','',''),(4,-1,'Pets','default_3x3',8,1,4,'1','1','pets','NORMAL','','catalog_frontpage_headline_shop_EN','','','','',''),(5,-1,'Building','default_3x3',263,1,5,'1','1','building','NORMAL','','catalog_header_roombuilder','','','','',''),(6,675,'Furnimatic','default_3x3',65,7,3,'0','0','furnimatic','NORMAL','','',' ',' ','',' ',''),(7,-1,'Staff','default_3x3',65,4,7,'1','1','staff','NORMAL','','','','','','',''),(8,2,'Habbo Club','vip_buy',172,1,11,'1','1','habbo_club','NORMAL','','catalog_club_headline1_en','club','','','',''),(9,2,'Bots','bots',65,1,13,'1','1','bots','NORMAL','','catalog_bots_headline1_en','catalog_bots_headline1_en','','They walk, they talk, and they make the perfect addition to any room!','',''),(10,220,'My Sales','marketplace_own_items',70,1,1,'1','1','my_sales','NORMAL','','','','','','',''),(11,220,'Offers','marketplace',71,1,2,'1','1','offers','NORMAL','','','','marketplace_offers','','',''),(12,2,'Credit Furni','default_3x3',146,1,1,'1','1','credit_furni','NORMAL','','catalog_bank_headline1','catalog_bank_teaser','','Habbo Exchange is where you can convert your Credits into a tradable currency. You can then use this currency to trade for Furni or just show off your riches in your room.','',''),(13,603,'Spaces','spaces_new',225,1,8,'1','1','spaces','NORMAL','','look_feel_text','','','Floors, wallpapers, landscapes - get a groovy combination for your room. Use our virtual room preview below to test out the combinations before you buy. Select the design and colour you like and click buy.','',''),(14,2,'Limited Rares','default_3x3',145,1,6,'1','1','limited_rares','NORMAL','','limited_header','catalog_limited_teaser_en','','These are only available for a limited time!','',''),(15,8,'Club Gifts','club_gift',172,1,1,'0','0','club_gifts','NORMAL','','','','','This is currently not coded in Morningstar.','',''),(16,604,'Lighting','default_3x3',115,1,6,'1','1','lighting','NORMAL','','catalog_dimmers_header1_en','catalog_dimmer_teaser_en','','Check out the Mood Lights. Use these items to dim the light in your rooms. Try out different light settings with different wallpapers to see what you get. Talk about lighting with style!',NULL,NULL),(17,568,'Mode','default_3x3',39,1,7,'1','1','mode','NORMAL','','catalog_mode_headline1','catalog_mode_teaser1','','Steely functionality combined with a sleek designer upholstery. The Habbo who chooses this furniture is a cool urban cat - streetwise, sassy and so slightly untouchable.','',''),(18,568,'Lodge','default_3x3',37,1,6,'1','1','lodge','NORMAL','','catalog_lodge_headline1','catalog_lodge_teaser1','','For that splendid ski-lodge effect with an open fire and whisky on the sidebar. This range is for those who appreicate the true beauty of solid wood.','',''),(19,511,'Colourable Plasto','default_3x3_color_grouping',46,1,1,'1','1','colourable_plasto','NORMAL','','plastic','plastic_pasic_promo_1','','Throw on an afro and grab a disco ball! Feel that retro, 1970s vibe? You soon will with this colourful, plastic range! Choose a colour to suit your mood and off you go!','',''),(20,602,'Vegetation','default_3x3',220,1,2,'1','1','vegetation','NORMAL','','catalog_plants_headline1','catalog_plants_teaser1','','Every room needs a plant! Not only do they bring a bit of the outside inside, they also enhance the air quality! And what better gift for a friend than a beautiful rose or elegant fruit tree...','',''),(21,603,'Walls','default_3x3',122,1,3,'1','1','walls','NORMAL','','catalog_walls_header_dyn','catalog_walls_teaser2_001','','Bring the outdoors in with windows and posters. Transform your surroundings - your walls will never look bare again!','',''),(22,209,'Accessories','default_3x3',11,1,2,'1','1','accessories','NORMAL','','catalog_extra_headline1','catalog_extra_teaser1','','However you place your essential Furniture, it\'s the finishing touches that count!','',''),(23,526,'Pixel Rentals','default_3x3',5,1,7,'1','1','pixel_rentals','NORMAL','','tienda-pixel','pixel3','','','',''),(24,209,'Base','default_3x3',179,1,11,'1','1','base','NORMAL','','catalog_header_base','base_rentable_teaser','','This colourful range of furni has everything you need to style out your room and build great spaces.','',''),(25,604,'Badge Display','badge_display',224,1,10,'1','1','badge_display','NORMAL','','catalog_header_badgedisplay','badgedisplay_promo2','','You worked hard to get your badges, right? Now\'s the time to show it off, grab a display case and choose your favorite badge to show off!','',''),(26,2,'Room Event','roomads',55,1,3,'1','1','room_event','NORMAL','','events_header','','','','',''),(27,568,'Iced','default_3x3',72,1,4,'1','1','iced','NORMAL','','catalog_iced_headline1','catalog_iced_teaser1','','It\'s so chic, it says everything and nothing. It\'s a blank canvas, let your imagination run wild!','',''),(28,209,'Alhambra','default_3x3',12,1,4,'1','1','alhambra','NORMAL','','alhambra_header','alhambra_teaser','','For the cold Arabian nights and hot Arabian days, you\'ll need a palace.. And we have just what you need! Green blossom print should cover it just fine!','',''),(29,209,'Glass','default_3x3',29,1,29,'1','1','glass','NORMAL','','catalog_glass_headline1','catalog_glass_teaser1','','You can really open up a space with this stylish glass furniture, just don\'t walk into it!','',''),(30,209,'Gothic','default_3x3',30,1,30,'1','1','gothic','NORMAL','','catalog_gothic_headline1','catalog_gothic_teaser1','','As the church bells ring out midnight, you walk through your cobbled hall lit by candles, throw yourself into your medieval throne and paint your nails black. This is what we imagined when we ordered this range!','',''),(31,209,'Japan','default_3x3',36,1,38,'1','1','japan','NORMAL','','catalog_jap_headline1','catalog_jap_teaser3_en','','We have sushi, tatami and katana\'s! I have no idea what the difference is, but I sure know its Japanese! Fulfil your fantasies and buy some today!','',''),(32,209,'Lost Tribe','default_3x3',38,1,44,'1','1','lost_tribe','NORMAL','','losttribe','LT_teaser_en','','Start your own tribal village with our ancient furniture, all carved from hard wearing stone. NOTE: Lava is hot, get an adult to help you.','',''),(33,209,'Neon','default_3x3',41,1,50,'1','1','neon','NORMAL','','catalog_neon_header1_en','catalog_neon_teaser1_en','','Party animals rejoice! Feel the base and reach for the lasers with the Neon Furni range - everything you need to get the party started!','',''),(34,209,'Relax','default_3x3',49,1,60,'1','1','relax','NORMAL','','rela_header_en','rela_teaser_en','','Relax after a busy day in the Welcome Lounge. Light a few candles, and chill out with a good read in a wicker chair. We understand the needs of a Wulles with a hectic lifestyle!','',''),(35,209,'Romantique','default_3x3',50,1,61,'1','1','romantique','NORMAL','','catalog_romantique_headline1','catalog_rom_teaser_en','','Found in a French barn, this sweet but sexily romantic range caters to every ladies needs. Just going to powder my nose!','',''),(36,209,'Scifi','default_3x3',53,1,65,'1','1','scifi','NORMAL','','sf_header_en','sf_teaser_en','','Sci Fi convention, outer space, the Moon, we have everything you need to make your own mystical, un-earthly room right here!','',''),(37,376,'2009 - Shalimar','default_3x3',62,1,3,'1','1','2009_shalimar','NORMAL','','catalog_shal_header1_en','catalog_shal_teaser_en','','Based on Bollywood!','',''),(38,219,'Freeze!','default_3x3',87,1,5,'1','1','freeze!','NORMAL','','catalog_freeze_en','ctlg_teaser_es','','Freeze!... and try the newest game to hit Wulles! Team up and plant snowball bombs to snap freeze your competitors. You could say it\'s so cool, it\'s frozen ;)','',''),(39,526,'Pixel Collectibles','default_3x3',5,1,5,'1','1','pixel_collectibles','NORMAL','','tienda-pixel','pixel3','','','',''),(40,7,'Ads Room Backgrounds','default_3x3',47,6,1,'1','1','ads_room_backgrounds','NORMAL','','','','','Use these to place images in your room. The mpu\'s go to a link when clicked; the AD one does not.','',''),(41,387,'Theatredome','default_3x3',264,1,25,'1','1','theatredome','NORMAL','','catalog_header_classics','article_habboreport2','','The Theatredrome is a very old and popular Public Room. It\'s hosted many campaigns from paying sponsors.','',''),(42,604,'Rollers','default_3x3',222,1,9,'1','1','rollers','NORMAL','','catalog_roller_headline1','catalog_teaser_rollers_en','','Move your imagination. This cool stuff is more than suitable for business and pleasure... Habbo rollers for games and queues. Now available in multipacks.','',''),(43,209,'Diner','default_3x3',204,1,23,'1','0','diner','NORMAL','','diner','catalog_diner_teaser_en','','Originally from the 50\'s this furni has been refurbished and put right into the catalogue! Use this with the Kitchen range for ultimate diner experience!','',''),(44,442,'Twilight','default_3x3',52,4,66,'1','1','twilight','NORMAL','','catalog_twilight_header_en','ctlg_pic_ads_twi_mist','','I\'ve never read the book, all I know is it has vampires playing basket ball and some heart throb called Edward Cullen, but the furni looks good!','',''),(45,219,'Battle Banzai','default_3x3',78,1,3,'1','1','battle_banzai','NORMAL','','catalog_battleBanzai_header_en','catalog_battleBanzai_teaser','','Bigger, Better, Bouncier - it\'s Battle Banzai! Now YOU set the rules for your own game, in your own room. You got the Banzai Power!','',''),(46,209,'Trax','default_3x3',4,1,74,'1','1','trax','NORMAL','','hotelhits_catalog_header','hotelhits_teaser','','Trax are the Habbo music disks which have many multiple tunes installed onto them which can be played on a Trax Machine in the room. After the Habbo transistion from Shockwave to Flash clients, the trax system was not recovered until April 2011, where only Juke Boxes, old CDs, and Habbo sold CDs were re-released.','','For decoration only.. They do not function.'),(47,526,'Hello','default_3x3',5,1,3,'1','1','hello','NORMAL','','tienda-pixel','pixel3','','','',''),(48,526,'Automobile','default_3x3',5,1,1,'1','1','automobile','NORMAL','','tienda-pixel','pixel3','','','',''),(49,442,'Goodbye Big Hand','default_3x3',52,4,26,'1','1','goodbye_big_hand','NORMAL','','','','','','',''),(50,376,'2010 - Bling','default_3x3',62,1,5,'1','1','2010_bling','NORMAL','','catalog_header_bling_en','catalog_teaser_bling11','','Did someone speak in glamour? Chic? Lux? So you\'re speaking the language of Bonnie Blonde, my friend!','',''),(51,209,'Organo','default_3x3',235,1,51,'1','1','organo','NORMAL','','organo_cata_header','organo_teaser','','The latest range from Ann Summers, the Orgie line. Made of soft, wipe clean plastic, its perfect for any three, four or fivesome!','',''),(52,234,'Pet Food','default_3x3',201,1,2,'1','1','pet_food','NORMAL','','catalog_header_petfood','ctlg_pet_teaser1','','Keep your Pet happy and healthy. Feed it and don\'t forget about exercise!','',''),(53,209,'Runway','default_3x3',74,1,62,'1','1','runway','NORMAL','','runway_header_en','runway_teaser_en','','Spice up your salon, hair parlour or boutique with our stylish yet practical range! From sewing machines to comfy seating, we\'ve got the perfect option for you.','',''),(54,209,'Prison','default_3x3',240,1,57,'1','1','prison','NORMAL','','prisonheader','prisonteaser','','Hey, he\'s escaping! Just kidding, no one\'s getting out of these high security cells!','',''),(55,209,'TV Studio','default_3x3',136,1,76,'1','1','tv_studio','NORMAL','','header_studio','teaser_studio','','The Studio range lets YOU be your own music producer!','',''),(56,209,'Cubie','default_3x3',100,1,20,'1','1','cubie','NORMAL','','catalog_cubie_header_en','catalog_cubie_teaser','','It\'s sleek, it\'s modern, it\'s so darn cool it can barely stand itself... Introducing the Cubie Furni range! Give your Bachelor or Bachelorette pad a homely feel with a sophisticated twist.','',''),(57,209,'Waasa','default_3x3',103,1,80,'1','1','waasa','NORMAL','','waasa_catalogue_header','waasa_teaser','','Waasa is the perfect furniture for a chilled, laidback room. Especially good for students on a budget!','',''),(58,442,'American Idol','default_3x3',52,4,3,'1','1','american_idol','NORMAL','','catalog_header_AI1_en','catalog_teaser_idol','','Host your own American Idol show with this replica furniture! All that\'s missing is a Randy Jackson lookalike!','',''),(59,209,'Kitchen','default_3x3',217,1,41,'1','1','kitchen','NORMAL','','catalog_header_kitchen2015','teaser_kitchen2015','','Fancy owning a Habbo restaurant? Or just love catering for Habbos in style? With this furni line you can REALLY get cooking!','',''),(60,209,'USVA','default_3x3',129,1,78,'1','0','usva','NORMAL','','catalog_header_USVA','Catalog_teaser_USVA','','With a great range of colours and new stacking possibilities, you\'ll love building and creating structures with the new USVA Furni line!','',''),(61,190,'Santorini Crackables','default_3x3',42,1,11,'1','1','santorini_crackables','NORMAL','','','','',NULL,NULL,NULL),(62,209,'Mystics','default_3x3',185,1,48,'1','1','mystics','NORMAL','','header_mystics','teaser_mystics','','A mystic crystal has crashed outside the hotel bounds and is transforming the hotel into an infected wilderness. Will you fight for the side for good? Or will you fight for the side of evil and help the infection spread?','',''),(63,218,'Triggers','default_3x3',81,1,3,'1','1','triggers','NORMAL','','catalog_wired_header2_en','ctlg_pic_wired_triggers','','Triggers let you define what needs to happen for an Effect to take place. To program a Trigger, place it in a room, double click on it and set it up! You need to stack an Effect with the Trigger to make it work.',NULL,NULL),(64,218,'Effects','default_3x3',82,1,4,'1','1','effects','NORMAL','','catalog_wired_header3_en','ctlg_pic_wired_effects','','Effects are what happens after you activate a Trigger. To program an Effect, place it in a room, double click on it and set it up! You will always need to stack a Trigger with the Effect to make it work.',NULL,''),(65,218,'Conditions','default_3x3',83,1,5,'1','1','conditions','NORMAL','','catalog_wired_header4_en','ctlg_pic_wired_conditions','','Conditions are specific things that need to be done before a Trigger will work. If you want to use a Condition, you will need to stack it with a Trigger and Effect.',NULL,''),(66,442,'Stray Pixels','default_3x3',52,4,61,'1','1','stray_pixels','NORMAL','','StrayPixelsLogo','catalog_pxl_teaser2_nl','','','',''),(67,209,'Mayan','default_3x3',171,1,45,'1','1','mayan','NORMAL','','mayanheader2','mayanteaser','','Just what you need to prove you survived the apocolypse!','',''),(68,209,'African','default_3x3',233,1,3,'1','1','african','NORMAL','','african_header','african_catateaser','','The new African furniture range is here!','',''),(69,209,'Anna','default_3x3',104,1,6,'1','1','anna','NORMAL','','catalog_anna_header','catalog_anna_teaser','','Make the new Anna range yours!','',''),(70,209,'Steampunk','default_3x3',180,1,67,'1','1','steampunk','NORMAL','','catalog_header_steampunk','catalog_teaser_steampunk','','Infuse your room design with the power of steam! This Steampunk line is a full set of building material to create amazing room designs that resemble an alternate retro-futuristic universe.','',''),(71,602,'Tents','default_3x3',223,1,6,'1','1','tents','NORMAL','','catalog_header_tents','catalog_teaser_tents','','Want some privacy? Go inside a tent to have private conversations in public places. Habbos outside will not see your chat nor will they see what\'s happening on the inside.','',''),(72,708,'Pirates','default_3x3',190,1,53,'1','1','pirates','NORMAL','','catalog_header_pirate','pirate_bundle','','Yarrr! Harrrrr! Fiddle dee dee, being a pirate is alright with me!','',''),(73,442,'Calippo','default_3x3',52,4,8,'1','1','calippo','NORMAL','','calippo_header_es','','',NULL,'',''),(74,209,'Habbo Stars','default_3x3',196,1,32,'1','1','habbo_stars','NORMAL','','habbostars1','habbostars2','','Have you always wanted to be famous? Is singing, dancing, or acting your thing? Well we have the next best thing, Wulles Stars! Get your dancing feet on and make your name shine!','',''),(75,277,'Dogs','pets',24,1,13,'1','1','dogs','NORMAL','','catalog_pet_headline1','','','Wet noses, paws and woofs! You\'re about to enter the world of Habbo Dogs. An adorable and cuddly ball of fur awaits you with a waggling tail.','Name your Dog:','Pick a colour:'),(76,277,'Cats','pets',20,1,14,'1','1','cats','NORMAL','','catalog_pet_headline1','','','Fluff, whiskers, meows and purrs! These cute little critters make great playmates and will keep you entertained.','Name your Cat:','Pick a colour:'),(77,277,'Crocs','pets',22,1,10,'1','1','crocs','NORMAL','','catalog_pet_headline1','','','Scaly skin, growls and snaps! Security for your room or used to scare your friends - this surprisingly loving Croc can be yours.','Name your Croc:','Pick a colour:'),(78,277,'Terriers','pets',66,1,7,'1','1','terriers','NORMAL','','catalog_pet_headline1','','','The Cairn Terrier is one of the oldest terrier breeds. From the Scottish Highlands, it was used for hunting prey among the cairns! Different breeds have different colours!','Name your Terrier:','Pick a colour:'),(79,277,'Bears','pets',68,1,5,'1','1','bears','NORMAL','','catalog_pet_headline1','','','A large mammal that walks on the soles of its feet, with thick fur and a short tail. Did you know that bears are related to dogs and that most species are omnivorous?','Name your Bear:',NULL),(80,277,'Pigs','pets',67,1,15,'1','1','pig','NORMAL','','catalog_pet_headline1','','','Finally an excuse to leave your room looking like a pigsty! Mischevious and cute, these little guys are out of the ordinary. Sweet and funny, a pet like no other!','Name your Pet Pig:','Pick a colour:'),(81,277,'Lion','pets',76,1,8,'1','1','lion','NORMAL','','catalog_pet_headline1','','','A boisterous predator in nature, the lion has been tamed to be your fierce friend in Habbo Hotel.','Name your pet:','Choose a colour:'),(82,277,'Rhino','pets',77,1,11,'1','1','rhino','NORMAL','','catalog_pet_headline1','','','The Rhinoceros is an African herbivore that can weigh over a ton. It is proud and slightly aloof, but loyal and never let anything get in the way of a good time!','Name your pet:','Choose a colour:'),(83,277,'Spider','pets',95,1,12,'1','1','spider','NORMAL','','catalog_pet_headline1','','','One of the most feared creatures in nature, and perhaps the most misunderstood. The majority of Spiders have sharp fangs that inject venom into their prey- but don\'t worry, these spiders won\'t bite! Maybe...','','Name your pet:'),(84,277,'Turtles','pets',126,1,9,'1','1','turtle','NORMAL','','catalog_pet_headline1','','','Anything but slow, these guys are ready to ride the waves and swim laps at your beaches!','','Name your Turtle:'),(85,680,'Chick','pets',107,1,99,'1','1','chick','NORMAL','','catalog_pet_headline1','','',NULL,'','Name your Dragon:'),(86,277,'Frog','pets',97,1,16,'1','1','frog','NORMAL','','catalog_pet_headline1','','','Cute, green and slimy! Frogs come in a variety of colours and can be found all over the world. They are great jumpers and make great pets, but are harder to hold onto than a supermodel in a tornado.','','Name your Frog:'),(87,277,'Dragons','pets',109,1,6,'1','1','dragon','NORMAL','','catalog_pet_headline1','','','Keepers of the Dragon, beware...their history is legendary... With their fiery breath and scaly skin, these mythical creatures are nothing but fierce!','','Name your Dragon:'),(88,277,'Pet Monkey','pets',166,1,2,'1','1','monkey','NORMAL','','catalog_pet_headline1','','','This mischevious monkey has made his way into the hotel and into our hearts. From the tilted beret to his love of bunches of bananas- this Monkey is sure to liven up your Habbo life!','','Name your Monkey:'),(89,277,'Pet Horse','pets',132,1,1,'1','1','horse','NORMAL','','catalog_horse_header2_en','','','You can ride your horse around the Hotel and customize its body and hair colour.','','Name your Horse:'),(90,680,'Bunny','pets',148,1,99,'1','1','bunny','NORMAL','','babypets_cata_header','','','OINK! Partial to a good roll in the mud, these playful piggies have trotted into the hotel and are ready for fun!','','Name your Piglet:'),(91,680,'Bunny - Bad','pets',151,1,99,'1','1','bunny_bad','NORMAL','','catalog_horse_header2_en','','','You can ride your horse around the Hotel and also customize its body and hair colour.','','Name Your Horse:'),(92,680,'Bunny - Bored','pets',150,1,99,'1','1','bunny_bored','NORMAL','','catalog_pet_headline1','','','These mischievous little pets have travelled all the way from the deep jungles of WobbahLand! Adorable as they are naughty, these little guys love a good sing-a-long.','','Name your Obbah Wobbah:'),(93,680,'Bunny - Manic','pets',149,1,99,'1','1','bunny_manic','NORMAL','','catalog_pet_headline1','','','One of the most feared creatures in nature, and perhaps the most misunderstood. The majority of Spiders have sharp fangs that inject venom into their prey- but don\'t worry, these spiders won\'t bite ! Maybe...','','Name your pet:'),(94,680,'Pigeon - Wise','pets',2,1,99,'1','1','pigeon_wise','NORMAL','','','','','','',''),(95,680,'Pigeon - Cunning','pets',2,1,99,'1','1','pigeon_cunning','NORMAL','','','','','','',''),(96,680,'Monkey - Evil','pets',167,1,99,'1','1','monkey_evil','NORMAL','','','','','','',''),(97,680,'Bear Cubs','pets',228,1,1,'1','1','bear_cubs','NORMAL','','catalog_pet_headline1','','','','',''),(98,680,'Terrier Puppies','pets',228,1,5,'1','1','terrier_puppies','NORMAL','','catalog_pet_headline1','','','','',''),(99,221,'Kittens','pets',228,1,2,'1','1','kittens','NORMAL','','catalog_pet_headline1','','','Leaping their way around the Hotel, these fluffy furballs are here to steal your heart...and your yarn!','','Name your pet:'),(100,221,'Puppies','pets',228,1,1,'1','1','puppies','NORMAL','','catalog_pet_headline1','','','So soft and cuddly, these playful pups are certain to melt your heart. From Labradors to Dalmatians, there\'s a breed for everyone!','','Name your pet:'),(101,221,'Piglets','pets',228,1,3,'1','1','piglets','NORMAL','','catalog_pet_headline1','','','OINK! Partial to a good roll in the mud, these playful piggies have trotted into the hotel and are ready for fun!','','Name your pet:'),(102,277,'Velociraptor Pet','single_bundle',260,1,3,'1','1','velociraptor','NORMAL','','jurassic15_catalog_header','dino_pets','','Swift and sneaky, these reptiles have a reputation for being somewhat high-maintenance, incredibly intellectual and endlessly troublesome! You\'ll often find them pondering over deeply philosophical questions, or enjoying the finer things in life, like pedicures and meat straight off the bone.','',''),(103,190,'Coral Kingdom Crackables','default_3x3',42,1,4,'1','1','coral_kingdom_crackables','NORMAL','','','','',NULL,NULL,NULL),(104,209,'Drago','default_3x3',110,1,24,'1','1','drago','NORMAL','','drago_catalog_header2','drago_catalog_teaser2','','Dungeon furniture, the perfect range to create your torturous cellars!','',''),(105,568,'Dark Pura','default_3x3',48,1,10,'1','0','dark_pura','NORMAL','','puraheader','catalog_pura_teaser1','','The cleanest, freshest range. You can almost hear it breathe cool and tranquility within your room.','',''),(106,209,